#include<bits/stdc++.h>
using namespace std;
int n,max1,max2;
vector<pair<int,int>> mp[10010];
int dis1[100010],dis2[100010];
void dfs(int *dis,int x,int fa=-1)
{
    if(dis[x]>max1)
    {
        max1=dis[x];
        max2=x;
    }
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        if(v!=fa)
        {
            dis[v]=dis[x]+val;
            dfs(dis,v,x);
        }
    }
}
int main()
{
    while(scanf("%d",&n)==1)
    {
        for(int i=1;i<=n;i++)
        {
            mp[i].clear();
        }
        for(int i=2;i<=n;i++)
        {
            int x,v;
            scanf("%d%d",&x,&v);
            mp[i].push_back(make_pair(x,v));
            mp[x].push_back(make_pair(i,v));
        }
        memset(dis1,0,sizeof(dis1));
        memset(dis2,0,sizeof(dis2));
        max1=-1;
        dfs(dis1,1);
        int st=max2;
        max1=-1;
        dis1[st]=0;
        dfs(dis1,st);
        max1=-1;
        dfs(dis2,max2);
        for(int i=1;i<=n;i++)
        {
            printf("%d\n",max(dis1[i]+dis1[max2],dis2[i]));
        }
    }
    return 0;
}
